1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
3	const THREE_RUNES_BLOCK_PRICE = 60;
4	
5	const BASE_PRICE_BY_TYPE: Record<string, number> = {
6	  potion: 40,
7	  amulet: 60,
8	  staff: 80,
9	  sword: 100,
10	  rune: 25,
11	};
12	
13	export function quote(input: { customer: { yearsWithMHPCO: number }; items: { type: string }[] }): number {
14	  const items = input.items;
15	  const rawBasePrice = items.reduce((sum, item) => sum + BASE_PRICE_BY_TYPE[item.type], 0);
16	  const isThreeAlikeRunes = items.length === 3 && items.every((item) => item.type === "rune");
17	  const basePrice = isThreeAlikeRunes ? THREE_RUNES_BLOCK_PRICE : rawBasePrice;
18	  const firstInsuranceSurcharge = basePrice * FIRST_INSURANCE_SURCHARGE_RATE;
19	  const premium = basePrice + firstInsuranceSurcharge + PROCESSING_FEE;
20	  return Math.ceil(premium);
21	}
